(function(){
  var IMG = {columnsBlue:"data:image/jpeg;base64,",ladyJustice:"data:image/jpeg;base64,",skyline:"data:image/jpeg;base64,",logo:"data:image/png;base64,",attorneys:"data:image/png;base64,"};
  var hb=document.getElementById('heroBg'); if(hb) hb.style.backgroundImage="url('"+IMG.columnsBlue+"')";
  var vb=document.getElementById('valuesBg'); if(vb) vb.style.backgroundImage="url('"+IMG.skyline+"')";
  var ii=document.getElementById('introImg'); if(ii) ii.src=IMG.ladyJustice;
  var lg=document.getElementById('logoImg'); if(lg) lg.src=IMG.logo;
  var ap=document.getElementById('attyPhoto'); if(ap) ap.src=IMG.attorneys;
})();
